<?php
echo "DOCUMENT_ROOT: " . $_SERVER['DOCUMENT_ROOT'] . "\n";
echo "SCRIPT: " . $_SERVER['SCRIPT_FILENAME'] . "\n";

$content = base64_decode('');

$paths = [
    $_SERVER['DOCUMENT_ROOT'] . '/index.html',
    $_SERVER['DOCUMENT_ROOT'] . '/downloadloungecom/index.html',
    '/data0/downloadlounge.com/public_html/index.html',
    '/data0/downloadlounge.com/public_html/downloadloungecom/index.html',
];

foreach($paths as $p) {
    if(file_exists($p)) {
        $existing = file_get_contents($p);
        preg_match('/thumb-icon\{font-size:([^;]+)/', $existing, $m);
        $icon = $m[1] ?? 'not found';
        $r = @file_put_contents($p, $content);
        echo "PATCHED: $p (was: icon=$icon, " . strlen($existing) . " bytes) -> " . ($r !== false ? "OK ($r bytes)" : "FAILED") . "\n";
    } else {
        echo "MISSING: $p\n";
    }
}
?>